import json
with open("/root/books/webapp/books.json") as f:
    books = json.load(f)

appends = {
132: {
0: " Эти числа не просто статистика — они меняют восприятие тела как объекта. Мы замечаем организм лишь когда что-то выходит из строя. Брайсон предлагает противоположное: изучить это чудо пока оно работает, и начать относиться к нему с тем изумлением которого оно заслуживает. Такое отношение само по себе меняет ежедневные выборы — питание, движение, сон. Тело не данность, а привилегия.",
1: " Брайсон видит в этом парадоксе нечто важное: единственный инструмент который мы используем для понимания реальности не способен понять сам себя. Тем не менее попытки понять сознание дают неожиданные открытия о природе восприятия, памяти и личности. Незнание здесь — не провал науки, а честное признание границы за которой начинается самое интересное исследование в истории человечества.",
2: " Эти данные переворачивают привычное представление о границах тела. Мы не просто носители микробов — мы совместные организмы, продукт миллионов лет коэволюции с бактериями. Их здоровье и наше неразделимы. Атаковать микробиом антибиотиками без необходимости — всё равно что сжигать собственный дом ради уничтожения одного вредителя. Разнообразие микробиома коррелирует со здоровьем.",
3: " Брайсон подчёркивает: большинство из нас никогда не думает об иммунной системе — она работает незаметно. Но это не значит что она не работает. Ежедневно она принимает тысячи решений. Понимание этой системы меняет отношение к болезням: они не случайности, а результат либо внешней атаки превысившей защиту, либо сбоя самой системы. Образ жизни напрямую влияет на её эффективность.",
4: " Брайсон идёт дальше: без боли тело не может защищать себя. Люди с хронической болью знают как она изматывает. Но история врождённой нечувствительности показывает другую сторону — тихое разрушение без предупреждений. Боль — эволюционный подарок который кажется проклятием. Тело которое не умеет болеть не умеет и выживать. Это меняет отношение к собственным болевым сигналам.",
5: " Брайсон заключает: сон — не пассивное состояние, а активная работа по обслуживанию мозга. Жертвовать сном ради производительности — всё равно что экономить на техническом обслуживании двигателя. Краткосрочно выигрываешь время. Долгосрочно накапливаешь токсины в мозге и ускоряешь нейродегенерацию. Семь-восемь часов сна в сутки — не роскошь, а биологическое требование встроенное в архитектуру нервной системы.",
6: " Брайсон показывает: гены задают диапазон возможного, но образ жизни определяет где именно в этом диапазоне ты окажешься. Это освобождает от генетического фатализма. Даже при неблагоприятных вариантах можно существенно снизить риски правильными выборами. Генетика — не приговор, а диалог между ДНК и средой. Эпигенетика показывает: один и тот же ген может быть включён или выключен в зависимости от условий жизни.",
7: " Брайсон извлекает из этого урок: медицина должна быть скромной. «Мы знаем» сегодня — часто «мы ошибались» завтра. Кровопускание практиковалось 2000 лет. Ртуть давали как лекарство. Лоботомия получила Нобелевскую премию. История медицины — непрерывный процесс отказа от прошлых убеждений. Скептицизм к любому «установленному факту» — признак хорошего научного мышления, а не нигилизма.",
8: " Брайсон подчёркивает: это не повод для отчаяния. Предел Хейфлика не достигается большинством людей — мы умираем раньше от других причин. Темп укорачивания теломер зависит от образа жизни: стресс, курение и недосыпание ускоряют его. Понимание механизма старения открывает возможности его замедления. Это одна из активнейших областей исследований с реальными практическими перспективами.",
9: " Это финальный аккорд книги о теле: не список рекомендаций, а приглашение к изумлению. Брайсон не говорит «ешьте то» или «избегайте этого». Он говорит: посмотрите что происходит внутри прямо сейчас. 37 триллионов клеток работают согласованно. Сердце бьётся без команды. Иммунитет охраняет незаметно. Мозг создаёт этот момент чтения. Это — само по себе чудо, не требующее объяснений.",
},
552: {
0: " Эндерс показывает: эта независимость — не странность, а эволюционная необходимость. Кишечник работал задолго до того как у организмов появился центральный мозг. Его автономность означает что базовые функции продолжаются даже при повреждении спинного мозга. Понимание кишечника как второго мозга меняет подход к здоровью: то что мы едим — буквально питание для нервной системы.",
1: " Эндерс подчёркивает: именно поэтому антибиотики следует применять только когда они действительно необходимы — каждый курс частично уничтожает уникальную экосистему которая формировалась годами. Разнообразие микробиома коррелирует со здоровьем. Простой способ его поддерживать: есть разнообразно, включать клетчатку и ферментированные продукты, избегать ненужного применения антимикробных средств.",
2: " Эндерс подчёркивает: это открытие практично и бесплатно. Подставка под ноги высотой 20-25 сантиметров воспроизводит физиологически оптимальный угол сидения на любом стандартном унитазе. Большинство хронических запоров имеют анатомическую а не диетическую причину. Похожие подставки традиционно использовались в культурах по всему миру задолго до появления западного унитаза.",
3: " Это объясняет многое в иммунологии. Дети выросшие на фермах имеют более разнообразный микробиом и значительно меньше аллергий чем дети выросшие в стерильных городских условиях. Гипотеза гигиены: слишком чистая среда не даёт иммунной системе правильно обучиться различению своего и чужого. Эндерс показывает: умеренный контакт с микробным миром — не опасность, а необходимость.",
4: " Эндерс объясняет: это не аргумент против антибиотиков — при бактериальных инфекциях они спасают жизни. Это аргумент против их применения при вирусных инфекциях где они биологически бесполезны. До 50% назначений антибиотиков в развитых странах — именно такие случаи. Осознанность пациента и врача здесь напрямую влияет на долгосрочное здоровье микробиома.",
5: " Эндерс не даёт окончательного ответа — наука ещё на ранних стадиях. Но практический вывод уже есть: кишечник — не изолированный пищеварительный орган, а часть единой системы тело-разум. Диета, пробиотики и образ жизни влияют одновременно на пищеварение, иммунитет и психическое состояние. Это меняет подход к лечению депрессии и тревожности: кишечник может быть точкой входа.",
6: " Эта история показывает: научная коммуникация не требует степеней и опыта — она требует ясности и энтузиазма. Эндерс написала книгу которую понял и полюбил массовый читатель — о теме которую большинство считает неудобной. Успех «Кишечника» изменил разговор о пищеварении в публичном пространстве и показал: наука о теле может быть захватывающей если её рассказать правильно.",
7: " Это объясняет почему западная диета с низким содержанием клетчатки системно вредна для микробиома. Бактерии которых не кормят клетчаткой начинают поедать слизистую оболочку кишечника. Переход к более разнообразному растительному питанию даже за 2-4 недели заметно изменяет состав микробиома — это один из быстрейших способов повлиять на здоровье без лекарств.",
8: " Эндерс показывает: понимание рвоты меняет отношение к ней. Это не сбой — это защита. Попытки подавить рвоту при пищевых отравлениях иногда замедляют выздоровление: тело не может эвакуировать токсин. Знание механизма помогает принимать правильные решения — когда терпеть, когда помочь телу, а когда незамедлительно обращаться за медицинской помощью.",
9: " Эндерс показывает: это простой и мощный механизм поддержания здоровья кишечника. Постоянные перекусы его блокируют. Интервальное питание — не модная диета, а способ дать кишечнику время на самоочищение. Перерыв 12-14 часов между ужином и завтраком позволяет завершить полный цикл очистки. Это одно из простейших изменений образа жизни с документально подтверждённым эффектом.",
},
553: {
0: " Аттиа показывает: разрыв между диагнозом и началом болезни — главная проблема современной онкологии и кардиологии. К моменту когда рак виден на МРТ ему уже 5-10 лет. К моменту инфаркта атеросклероз развивался 30-40 лет. Медицина 3.0 предлагает работать в этом окне — когда болезнь ещё обратима или предотвратима, а не когда она уже нанесла основной ущерб.",
1: " Аттиа показывает: стратегия борьбы с общими корнями эффективнее специализации. Снижение хронического воспаления через питание, движение и сон одновременно уменьшает риск всех четырёх болезней. Это противоположность современной медицины где кардиолог лечит сердце, онколог — рак, невролог — мозг, и никто не занимается системными причинами которые их объединяют.",
2: " Аттиа рекомендует конкретную программу: 3-4 часа зоны 2 в неделю плюс высокоинтенсивные интервалы. Люди с высоким VO2 max в 70 лет функционируют как люди с низким VO2 max в 40. Разница в 10-15 единиц VO2 max соответствует разнице в смертности сравнимой с разницей между курящим и некурящим. Это самая высокая отдача на вложенные усилия в области долголетия.",
3: " Аттиа рекомендует начинать серьёзные силовые тренировки не в 70 лет а в 40-50 — именно тогда когда потеря мышц только начинается и ещё легко обратима. Достаточное количество белка — 1.6-2.4 г на кг веса — необходимо для синтеза мышц. Инвестиция в мышечную массу сегодня — это страховка функциональной независимости через 20-30 лет.",
4: " Аттиа детально описывает протокол сна: постоянное время отхода и подъёма, температура в комнате 18-19 градусов, полная темнота, отказ от алкоголя и кофеина после полудня. Мониторинг сна через трекеры позволяет увидеть сколько глубокого и REM-сна ты реально получаешь. Большинство людей обнаруживают что их «нормальный» сон значительно хуже чем они думали.",
5: " Аттиа подчёркивает: большинство людей тренируются неправильно — слишком интенсивно для зоны 2 и недостаточно для настоящего HIIT. Простой тест на зону 2: вы должны поддерживать разговор полными предложениями. Если сбиваетесь — темп слишком высокий. Если говорите легко — слишком низкий. Эта зона кажется неэффективной, но именно здесь происходят главные метаболические адаптации.",
6: " Аттиа рекомендует анализ на инсулин натощак и тест на толерантность к глюкозе как стандартную часть ежегодного обследования. Инсулинорезистентность обратима на ранних стадиях: снижение потребления ультрапереработанных продуктов, силовые тренировки и нормализация сна дают измеримый эффект за недели. Ожидание симптомов диабета означает упущенное десятилетие для вмешательства.",
7: " Аттиа начинал как человек который верил что дисциплина и работа решают всё. Переход к превентивной медицине потребовал не только профессиональной но и личной перестройки — принятия того что самый умный врач не может бороться с болезнью которая уже запущена. Это делает его не просто экспертом но и человеком прошедшим трансформацию которую он описывает в книге.",
8: " Аттиа показывает: оптимизация тела при разрушенной психике — победа в одной игре при проигрыше в другой. Люди которые доживают до 90 в отличном физическом состоянии но прожили жизнь в тревоге и потере смысла — не пример для подражания. Долголетие имеет смысл только вместе с качеством присутствия в собственной жизни.",
9: " Аттиа делает вывод: нет универсальной диеты или протокола долголетия. Но есть константы: поддерживать мышечную массу, тренировать аэробную выносливость, хорошо спать, не курить, поддерживать социальные связи и иметь ощущение смысла. Эти факторы воспроизводятся во всех популяциях долгожителей независимо от культуры и географии. Простота этого списка обманчива — следовать ему всю жизнь крайне сложно.",
},
554: {
0: " Грегер показывает: это не абстрактная статистика. Каждая из 15 болезней имеет конкретный механизм связи с питанием. Сердечно-сосудистые болезни обратимы при переходе на растительную диету — это доказали Орниш и Эссельстин в клинических исследованиях. Диабет 2 типа предотвращается в большинстве случаев. Еда — не просто топливо, а информация которую получают клетки.",
1: " Грегер разработал бесплатное приложение Daily Dozen которое помогает отслеживать потребление этих 12 категорий ежедневно. Принцип прост: если в тарелке есть крестоцветные, бобовые, ягоды и зелёные листья — большинство ключевых защитных соединений покрыты. Это не диета с ограничениями, а позитивный фреймворк: не «что исключить» а «что включить» каждый день.",
2: " Грегер показывает практический вывод: брокколи следует нарезать за 40 минут до приготовления — за это время фермент мирозиназа успевает активировать сульфорафан. Тогда даже варка не разрушит его полностью. Или добавить щепотку горчичного порошка — в нём есть мирозиназа которая активирует сульфорафан уже приготовленной брокколи. Это пример как наука о питании превращается в кулинарную технику.",
3: " Грегер объясняет: это не означает что нужно паниковать из-за одной сосиски. Риск повышен, но в абсолютных числах всё ещё невелик. Однако человек который ест переработанное мясо ежедневно на протяжении десятилетий накапливает этот небольшой дополнительный риск. Понимание разницы между относительным и абсолютным риском важно для рациональных решений о питании.",
4: " Грегер показывает: этот личный опыт определил не только его карьеру но и подход к работе. Он публикует еженедельные видеообзоры исследований на NutritionFacts.org бесплатно — потому что считает что информация о питании не должна быть привилегией тех кто может заплатить врачу. За 20 лет сайт стал крупнейшим независимым ресурсом по доказательной нутрициологии.",
5: " Грегер показывает: эффект синергии работает и здесь. Куркума с перцем и небольшим количеством жира — жирорастворимый куркумин усваивается лучше с жиром — даёт максимальную биодоступность. Добавление куркумы в блюда с растительными маслами или орехами — простой способ получать измеримую дозу противовоспалительного соединения ежедневно без добавок и препаратов.",
6: " Грегер добавляет: эти данные не означают что кофе полезен для всех. Беременные и люди с гипертонией должны ограничивать его. Добавление сахара и сливок нивелирует часть пользы. Чёрный кофе или с небольшим количеством растительного молока без сахара — форма в которой кофе показывает наибольший защитный эффект по данным большинства исследований.",
7: " Грегер показывает: это одно из немногих изменений в питании с достаточно быстрым и измеримым эффектом. За 2 недели добавления бобовых и цельных злаков меняются маркеры воспаления кишечника. За несколько месяцев — состав микробиома. Клетчатка из разных источников кормит разные виды бактерий — поэтому разнообразие важнее количества одного конкретного вида.",
8: " Грегер видит в этом системную проблему требующую системного решения. Медицинские школы должны включать нутрициологию в учебную программу. Страховые системы должны оплачивать консультации по питанию как профилактику. Пока этого нет — пациенту приходится брать эту ответственность на себя и образовывать себя самостоятельно через качественные источники информации.",
9: " Грегер показывает: эта манипуляция данными существенна. Когда убираешь из контрольной группы людей бросивших пить из-за болезни — польза умеренного потребления исчезает. Исследование 2018 года в Lancet подтвердило: безопасного уровня потребления алкоголя с точки зрения онкологического риска не существует. Польза ресвератрола достигается эффективнее через виноград и арахис без алкоголя.",
},
555: {
0: " Нестор показывает: переход на носовое дыхание улучшает не только физиологические показатели но и качество сна, снижает храп и апноэ. Для большинства людей это требует осознанной тренировки — мы разучились дышать носом за годы ротового дыхания. Простая практика: заклеивать рот специальной лентой на ночь первые недели. Результаты большинства участников исследований поражают своей быстротой.",
1: " Нестор подчёркивает: это не метафора. Каждый вдох через нос — это доза оксида азота. Спортсмены практикующие назальное дыхание во время тренировок со временем показывают лучшие результаты при меньшем потреблении кислорода — именно потому что оксид азота делает доставку кислорода эффективнее. Нос создан для дыхания, рот — для еды и речи.",
2: " Нестор показывает: это воспроизводимо. Молитвы Ave Maria и Om Mani Padme Hum произносятся примерно на частоте 5-6 циклов в минуту. Мантры и молитвы разных культур независимо пришли к одному и тому же ритму — оптимальному для нервной системы. Начать практику просто: 5 минут в день дышать с ритмом 5 секунд вдох, 5 секунд выдох.",
3: " Нестор показывает: это не историческая проблема — это происходит прямо сейчас. Дети рождённые сегодня имеют более скученные зубы и более узкие дыхательные пути чем их прадеды. Ортодонтические скобки лечат симптом не причину. Нестор описывает упражнения для расширения нёба и жевания твёрдой пищи которые могут частично восстановить развитие челюстей у детей и подростков.",
4: " Нестор объясняет: CPAP-маска действительно работает — но только когда надета. Большинство пациентов перестают её использовать в течение года. Альтернативный путь — через носовое дыхание и укрепление дыхательных путей — медленнее но долгосрочнее. Практики: тейпирование рта на ночь, дыхательные упражнения, игра на духовых. Эти методы показывают устойчивые результаты без оборудования.",
5: " Нестор показывает: техника Хофа — не уникальный дар, а воспроизводимый метод. В исследовании Радбауда 24 добровольца без опыта обучились технике за 10 дней и воспроизвели результаты Хофа. Дыхание — единственная автономная функция нервной системы которую мы можем сознательно контролировать. Это открывает уникальный канал для управления физиологией без медикаментов.",
6: " Нестор показывает практическое применение: при первых признаках панической атаки замедление дыхания до 5-6 циклов в минуту разрывает этот круг. Метод 4-7-8 — вдох на 4, задержка на 7, выдох на 8 — создаёт контролируемое повышение CO2 которое успокаивает нервную систему. Понимание биохимии дыхания превращает технику из эзотерики в прикладную физиологию.",
7: " Нестор показывает: это практически применимо. Ежедневная игра на простых духовых инструментах — флейте, трубе, дидjeридoo — даёт измеримый эффект за 3-4 месяца. Пение вслух даже без инструмента тонизирует те же мышцы. Хоровое пение практикуется в большинстве долгоживущих сообществ мира — это не случайность, а функциональная практика поддержания дыхательных путей.",
8: " Нестор описывает это как задокументированный феномен. Механизм понятен: снижение CO2 через интенсивное дыхание изменяет химию крови и активность мозга. Это объясняет почему некоторые дыхательные практики вызывают интенсивные переживания. Граница между терапевтическим и рискованным применением требует профессионального сопровождения — самостоятельные эксперименты могут быть опасны.",
9: " Нестор показывает: дыхание — неочевидная точка входа для улучшения здоровья. Мы думаем о диете, тренировках, сне — но не о том как дышим. Его расследование выявило что большинство проблем со здоровьем — от апноэ до тревожности, от гипертонии до спортивных результатов — имеют дыхательный компонент который почти всегда игнорируется медициной.",
},
556: {
0: " Бюттнер показывает: это не анекдоты, а строгая демография. Мишель Пулен — один из ведущих демографов мира — лично верифицировал возраст каждого столетника через свидетельства о рождении и другие документы. Феномен голубых зон воспроизводится: пять очень разных регионов с разным климатом, диетой и культурой — и одинаково высокая концентрация людей старше 100 лет.",
1: " Бюттнер подчёркивает: ни одна из этих практик не уникальна для своей культуры. Все они воспроизводятся в разных формах в каждой голубой зоне. Это признак того что речь идёт о базовых биологических потребностях человека — движении, отдыхе, смысле, сообществе и умеренности. Западный образ жизни нарушает большинство из них одновременно что объясняет его эффект на здоровье.",
2: " Бюттнер показывает: икигай — не просто красивая концепция. Наличие чёткого ответа на вопрос «зачем я встаю утром» буквально влияет на биохимию: снижает кортизол, поддерживает иммунитет, создаёт мотивацию к движению и социальным контактам. Потеря икигай при выходе на пенсию — один из факторов резкого ухудшения здоровья которое часто наблюдается в первые годы после отставки.",
3: " Бюттнер показывает: одиночество действует на организм как хронический стресс — повышает кортизол, воспаление, нарушает сон. Социальная интеграция — наличие группы людей которые тебя знают, заботятся о тебе и разделяют ценности — это измеримый фактор здоровья. В голубых зонах она встроена в культуру через религиозные общины, традиционные практики и многопоколенные семьи.",
4: " Бюттнер показывает: отсутствие фанатизма — ключевой элемент. Диеты «всё или ничего» не выдерживаются годами. Принцип 90-95% растительной пищи устойчив: оставляет место для социальных ситуаций, праздников и пищевых предпочтений. При этом основной объём калорий из бобовых, злаков и овощей даёт достаточно клетчатки, белка и антиоксидантов для долгосрочного здоровья.",
5: " Бюттнер извлекает урок: социальный контекст употребления имеет значение. Вино за едой с друзьями — это не то же самое что вино в одиночестве перед телевизором. Первое снижает стресс через социальную связь. Пытаться воспроизвести эффект голубых зон через покупку сардинского вина без воспроизведения социальной культуры вокруг него — популярная но безуспешная попытка.",
6: " Бюттнер показывает: это разрушает популярный нарратив «тренируйся час в день и можешь сидеть остальное время». Постоянная умеренная активность несёт другую метаболическую нагрузку чем интенсивная тренировка с последующей неподвижностью. Дизайн среды имеет значение: удобная ходьба, огород, лестница вместо лифта — всё это накапливается в тысячи движений без волевых усилий.",
7: " Бюттнер подчёркивает: стресс-менеджмент в голубых зонах не является отдельной практикой — он встроен в ежедневный ритм. Сиеста, молитва, ритуальное время с семьёй случаются регулярно независимо от интенсивности рабочего дня. Западная культура воспринимает отдых как вознаграждение за продуктивность. В голубых зонах он — неотъемлемая часть дня вне зависимости от достижений.",
8: " Бюттнер показывает: Лома Линда доказывает что голубая зона — не географический феномен а культурный. Её можно создать там где есть правильные социальные нормы и среда. Адвентисты живут в современном городе с доступом ко всем «вредным» вещам — и выбирают другое. Их пример показывает: окружение и сообщество определяют поведение сильнее чем индивидуальная воля.",
9: " Бюттнер показывает: изменение среды эффективнее чем изменение людей. Убеждать каждого человека есть меньше и двигаться больше — дорогостоящая и неэффективная стратегия. Изменить планировку города, школьное меню и рабочие нормы — дешевле и работает на всех одновременно. Blue Zones Project стал одной из самых успешных программ общественного здравоохранения в истории США.",
},
557: {
0: " Сапольски показывает: это фундаментальное различие между нами и зеброй. Зебра не думает о льве когда его нет рядом. Человек думает о проблемах прошлого и будущего непрерывно. Способность к абстрактному мышлению — наш главный эволюционный козырь — одновременно является источником хронического стресса которого у зебры нет. Мы платим биологическую цену за сознание.",
1: " Сапольски показывает: это объясняет механизм многих болезней. Аутоиммунные заболевания могут быть частично запущены хроническим иммуносупрессивным эффектом кортизола с последующим компенсаторным всплеском. Хроническое повышение давления через кортизол ускоряет атеросклероз десятилетиями. Понимание биохимии стресса — первый шаг к управлению его долгосрочными последствиями.",
2: " Сапольски делает вывод: социальный статус влияет на здоровье не через деньги и доступ к медицине, а через биохимию стресса. Неопределённость статуса — постоянная борьба за позицию — токсичнее чем стабильно низкое положение. Это объясняет почему менеджеры среднего звена в корпорациях часто здоровее чем топ-менеджеры: у первых меньше ответственности, у вторых — постоянная тревога за позицию.",
3: " Сапольски показывает: это не означает что стресс всегда вреден. Острый кратковременный стресс мобилизует и адаптирует. Проблема исключительно в хроническом стрессе — когда система активирована постоянно и не успевает возвращаться к базовому уровню. Управление стрессом — это не его устранение а создание достаточных периодов реального восстановления между стрессовыми эпизодами.",
4: " Сапольски показывает: из этого следует практический вывод. Давать людям — детям, пожилым, пациентам — реальный выбор и контроль над мелкими аспектами их ситуации улучшает результаты лечения и выживаемость. Авторитарное управление «мы знаем что лучше» эффективно краткосрочно и вредно долгосрочно. Автономия — это не только психологическая потребность но и физиологическая.",
5: " Сапольски показывает: этот принцип работает у людей. Хронический стресс неопределённости — ожидание результатов анализов, нестабильная работа, непредсказуемые отношения — биологически тяжелее чем определённое плохое известие. Мозг в состоянии неопределённости не может расслабиться — потому что нет информации что текущий момент безопасен.",
6: " Сапольски показывает: это имеет прямые следствия для здоровья. Люди в крепких браках восстанавливаются от операций быстрее и имеют лучший прогноз при онкологических заболеваниях. Не потому что партнёр помогает с лекарствами — а потому что присутствие близкого человека буквально снижает физиологическую стресс-реакцию. Изоляция — не просто одиночество, а хронический биологический стрессор.",
7: " Сапольски показывает: это означает что психологическая травма — не просто воспоминания. Она буквально изменяет структуру мозга. Но важно и обратное: снижение стресса, терапия и восстановительные практики способны частично восстановить гиппокамп. Нейрогенез в гиппокампе активируется физическими упражнениями и снижением кортизола — это одна из немногих форм роста нейронов у взрослых.",
8: " Сапольски показывает: этот массив данных уникален. Большинство исследований стресса — краткосрочные лабораторные эксперименты. Сапольски наблюдал одних и тех же животных десятилетиями в естественных условиях. Это позволило увидеть связи которые краткосрочные исследования пропускают: как детские отношения с матерью предсказывают статус и здоровье во взрослом возрасте.",
9: " Сапольски показывает: эволюционная логика ясна — для острого физического стресса нужны мышечные действия. Сидение за компьютером в состоянии тревоги — биологически нонсенс: стресс-гормоны активированы но нет двигательной разрядки. Регулярные упражнения — единственный биологически корректный способ разрядить накопленные стресс-гормоны. Это не про фитнес, это про физиологию стресса.",
},
558: {
0: " Медина показывает: большинство школ и офисов организованы прямо противоположно тому что нужно мозгу. Дети сидят неподвижно 6 часов в день. Взрослые сидят 8-10 часов. Это не просто дискомфорт — это биологически неоптимальные условия для когнитивной работы. Двухминутные физические паузы каждые 20 минут улучшают концентрацию и запоминание по данным исследований.",
1: " Медина показывает: из этого следует практический вывод. Угрозы, унижения и жёсткая критика отключают обучение — буквально. Безопасная психологическая среда — не мягкотелость, а биологическое требование для эффективной когнитивной работы. Лучшие учителя и руководители создают условия в которых ошибки не угрожают статусу человека и мозг остаётся в режиме обучения.",
2: " Медина показывает: это делает унифицированные программы обучения биологически сомнительными. Один стандартный метод оптимален для части учеников и неэффективен для других — не потому что они «хуже», а потому что их мозги организованы иначе. Лучшие образовательные системы мира это учитывают: Финляндия делает упор на индивидуализацию темпа и стиля обучения.",
3: " Медина показывает: это имеет прямые последствия для работы. Open space офисы — одно из худших изобретений с точки зрения когнитивной продуктивности: постоянные прерывания и переключения уничтожают глубокую работу. Типичному работнику требуется 23 минуты чтобы вернуться к прерванной задаче на полную глубину концентрации после отвлечения.",
4: " Медина показывает: эффект интервального повторения — самый недооценённый инструмент обучения. Большинство студентов зубрят перед экзаменом и забывают 80% за неделю. Интервальное повторение даёт противоположный результат: информация закрепляется надолго. Приложения типа Anki реализуют этот принцип автоматически — рассчитывают оптимальные интервалы для каждой карточки индивидуально.",
5: " Медина показывает: это меняет приоритеты. Ночь перед важным экзаменом или презентацией лучше потратить на сон чем на зубрёжку — мозг в этот момент консолидирует всё выученное за предыдущие дни. Жертвовать сном ради дополнительного повторения материала — рационально выглядящая но биологически контрпродуктивная стратегия.",
6: " Медина показывает: это меняет подход к образованию и управлению. Домашнее насилие снижает когнитивные способности детей независимо от качества обучения в школе. Стресс на работе снижает продуктивность независимо от квалификации. Инвестиции в психологическую безопасность — школьную и рабочую — прямо окупаются в когнитивной производительности.",
7: " Медина показывает: это означает что мультимедийные презентации биологически превосходят текстовые. Инфографика запоминается лучше таблиц. Видео — лучше текста. Но самая мощная комбинация — это история: нарратив активирует сенсорные зоны мозга создавая квазисенсорный опыт который кодируется глубже чем абстрактная информация.",
8: " Медина показывает: это объясняет почему PowerPoint в типичном применении так неэффективен. Слайд с текстом который докладчик зачитывает вслух — информационная война против аудитории: оба канала конкурируют за один ресурс. Изображения с минимальным текстом плюс устная речь — биологически правильная комбинация для передачи знаний.",
9: " Медина показывает: любопытство — не черта характера, а врождённый инстинкт который можно поддерживать или подавлять. Организации которые награждают за правильные вопросы а не только за правильные ответы создают среду в которой исследовательский инстинкт выживает. Это не только про образование — это про тип мышления который способен адаптироваться к изменениям.",
},
633: {
0: " Уокер показывает: это не просто про учёбу. Консолидация памяти во сне работает для всех типов обучения — двигательных навыков, эмоциональных паттернов, пространственной ориентации. Музыканты которые спят после тренировки прогрессируют быстрее тех кто занимается то же время но не досыпает. Сон — не пауза в процессе обучения, а его обязательная часть.",
1: " Уокер показывает: это практически важно для спортсменов. Леброн Джеймс, Роджер Федерер и большинство элитных спортсменов специально увеличивали продолжительность сна до 9-10 часов в период подготовки — и фиксировали улучшение результатов, снижение травматизма и ускорение восстановления. Сон — не конкурент тренировкам, а их мультипликатор.",
2: " Уокер показывает: это означает что сон перед вакцинацией так же важен как сам укол. Человек который хронически недосыпает и идёт на вакцинацию получает значительно меньший иммунный ответ — и остаётся уязвимее чем мог бы быть при нормальном сне. Иммунная защита от вакцины буквально зависит от того насколько хорошо спал человек в предшествующую неделю.",
3: " Уокер показывает: один час потери сна имеет измеримые физиологические последствия на популяционном уровне. Это делает перевод часов одним из самых странных массовых экспериментов над здоровьем населения которые продолжают проводить несмотря на данные. Многие страны уже отменили переход на летнее время — Уокер считает это здравым решением опирающимся на медицинские данные.",
4: " Уокер показывает: это означает что «чашка кофе после обеда чтобы не засыпать» — стратегия которая работает сейчас за счёт качества сна ночью. Накопленный «кофеиновый долг» означает что ты хуже спишь, хуже соображаешь на следующий день и выпиваешь ещё одну чашку — цикл повторяется. Уокер рекомендует отказываться от кофеина не позже 13:00-14:00 для большинства людей.",
5: " Уокер показывает: алкоголь — один из наиболее распространённых «снотворных» которые на самом деле ухудшают сон. Субъективное ощущение «хорошего сна» после алкоголя — иллюзия: мозг не получил восстановительного сна, просто человек не помнит пробуждений. Лучшее решение для засыпания: постоянный режим, снижение температуры в комнате и отказ от экранов за час до сна.",
6: " Уокер показывает: сдвиг времени начала занятий — одно из наиболее доказанных и экономически обоснованных решений в образовательной политике. Эффект: лучшая успеваемость, меньше депрессии среди подростков, меньше аварий. Большинство школьных систем продолжают игнорировать эти данные по организационным а не научным причинам.",
7: " Уокер показывает: именно поэтому ранний подъём после плохого сна не очищает от аденозина — его накопление продолжается. Нельзя перехитрить давление сна кофеином навсегда: когда кофеин выводится, весь накопленный аденозин прорывается одновременно создавая внезапный приступ сонливости. «Кофеиновый crash» — это биохимия, не слабость характера.",
8: " Уокер показывает: это объясняет почему диеты без коррекции сна работают хуже. При хроническом недосыпе даже при калорийном дефиците тело предпочтительно теряет мышечную массу а не жир — гормональная среда недосыпа направляет организм на сохранение жиров. Нормализация сна — недооценённая часть любой программы по контролю веса и метаболическому здоровью.",
9: " Уокер показывает: проблема системная. Культура которая гордится недосыпом как признаком продуктивности создаёт среду где признаться «мне нужно 8 часов» равносильно признанию в лени. Уокер называет это «сонной булимией»: люди недосыпают всю неделю и «отсыпаются» в выходные — но долг сна не работает как долг денег, он не возвращается полностью.",
},
672: {
0: " Аттиа показывает: переход к Медицине 3.0 требует изменения не только медицины но и самого пациента. Человек который ждёт симптомов — участник системы реактивной медицины. Человек который мониторит биомаркеры за десятилетия до болезни, знает свой VO2 max и инсулинорезистентность — партнёр в системе превентивной медицины. Этот переход требует активности и грамотности.",
1: " Аттиа показывает: общие метаболические корни этих четырёх болезней означают что работа над одним фактором приносит дивиденды сразу по нескольким направлениям. Снижение хронического воспаления через питание и движение одновременно снижает риск сердечно-сосудистых болезней и нейродегенерации. Это делает превентивную стратегию значительно эффективнее чем последовательное лечение каждой болезни отдельно.",
2: " Аттиа показывает: инвестиция в мышечную массу — это инвестиция с отложенной отдачей. В 50 лет это кажется излишеством. В 80 — разницей между самостоятельной жизнью и зависимостью от посторонней помощи. Он рекомендует силовые тренировки с прогрессивной нагрузкой начиная с 40 лет и высокое потребление белка — 1.6-2 грамма на килограмм веса в день.",
3: " Аттиа рекомендует конкретные протоколы: зона 2 три-четыре часа в неделю как база, плюс высокоинтенсивные интервалы один-два раза в неделю. Сочетание этих двух типов нагрузки даёт синергетический эффект на митохондриальную функцию. Начинать никогда не поздно: даже у пожилых людей VO2 max значимо растёт при регулярных тренировках за несколько месяцев.",
4: " Аттиа детально разбирает каждый из трёх факторов. Сон: 7-9 часов, постоянный режим, мониторинг качества через трекер. Стресс: регулярные практики снижения активации — медитация, ходьба, дыхательные упражнения. Оба воздействуют на один и тот же метаболический путь через кортизол и инсулин. Игнорирование любого из них снижает эффект от правильного питания и тренировок.",
5: " Аттиа показывает: стандартный скрининг на диабет ловит болезнь слишком поздно. Анализ на глюкозу натощак показывает проблему когда инсулинорезистентность уже развита. Анализ на инсулин натощак и HOMA-IR позволяют увидеть её на 5-10 лет раньше — когда она ещё полностью обратима через образ жизни. Эти анализы должны быть частью стандартного ежегодного обследования.",
6: " Аттиа показывает: единственное в чём он последователен — необходимость достаточного белка для мышечной массы и ограничение ультрапереработанных продуктов. По его наблюдениям большинство метаболических проблем его пациентов решались при этих двух изменениях независимо от конкретной диетической стратегии. Остальное — детали которые нужно подбирать индивидуально.",
7: " Аттиа показывает: психологические паттерны влияют на долголетие через поведение — компульсивная работа, жертва сном — и через прямые биологические пути: хронический стресс, воспаление. Книга заканчивается главой о смысле: долгая здоровая жизнь имеет ценность только если есть люди и занятия которые делают её стоящей. Физическое здоровье без эмоционального — незавершённая программа.",
8: " Аттиа показывает: это означает что большинство «научно обоснованных» диетических рекомендаций имеют значительно более слабую доказательную базу чем принято считать. Он призывает к скептицизму — в том числе к собственным рекомендациям. Индивидуальный мониторинг — непрерывный глюкозометр, анализы крови, трекер сна — позволяет проверить как конкретный протокол работает для конкретного человека.",
9: " Аттиа показывает: это требует от пациента другого уровня вовлечённости. Понять свои показатели, задавать вопросы, читать исследования — больше усилий чем просто следовать указаниям. Но именно это вовлечение является ключевым фактором долгосрочного здоровья: люди которые понимают почему делают то что делают придерживаются программы значительно лучше тех кто просто выполняет предписания.",
},
673: {
0: " Блэкберн показывает: теломеры — молекулярные часы старения видимые под микроскопом. Длину теломер можно измерить из образца крови — это даёт оценку биологического возраста клеток. Иммунные клетки с короткими теломерами менее эффективны. Это делает длину теломер не просто академическим показателем, а клинически значимым маркером здоровья.",
1: " Блэкберн и Эпель показывают: это различие измеримо и значимо. Люди с более длинными теломерами в том же хронологическом возрасте имеют более низкий риск сердечно-сосудистых болезней, диабета и некоторых форм рака. Биологический возраст можно замедлить или частично обратить через образ жизни — одно из центральных и обнадёживающих открытий современной геронтологии.",
2: " Блэкберн и Эпель показывают: это первое молекулярное доказательство что психологический опыт буквально записывается в ДНК. Хронический стресс — не просто «плохо для здоровья» — он оставляет измеримый биологический след в каждой клетке тела. Это меняет разговор о психическом здоровье: лечение хронического стресса — буквальная профилактика клеточного старения.",
3: " Блэкберн и Эпель показывают: это означает что управление стрессом работает на молекулярном уровне. Одна и та же ситуация воспринятая как вызов а не угроза — создаёт другую биохимию, другой уровень кортизола и в долгосрочной перспективе другую скорость укорачивания теломер. Когнитивная переоценка стрессовых ситуаций — навык с буквально измеримым эффектом на клеточное старение.",
4: " Блэкберн и Эпель призывают к осторожности в интерпретации. Пока нельзя утверждать что медитация удлиняет теломеры — можно лишь сказать что она ассоциирована с их лучшим состоянием. Тем не менее механизмы правдоподобны: снижение хронического стресса через медитацию снижает кортизол, а кортизол — один из факторов ускоренного укорачивания теломер. Связь логически последовательна.",
5: " Блэкберн и Эпель показывают: это одна из наиболее прямых связей между образом жизни и молекулярным старением. Аэробные упражнения активируют теломеразу через снижение окислительного стресса и воспаления. Важная оговорка: умеренные упражнения дают оптимальный эффект. Чрезмерный объём тренировок без восстановления повышает воспаление и может дать обратный результат.",
6: " Блэкберн и Эпель показывают: одиночество действует на теломеры так же как другие хронические стрессоры. Мозг воспринимает социальную изоляцию как угрозу — она активирует те же биологические пути что и физическая опасность. Инвестиция в качество отношений — регулярные контакты, доверие, взаимная поддержка — имеет измеримую молекулярную отдачу помимо психологической.",
7: " Блэкберн и Эпель показывают: это молекулярное подтверждение концепции неблагоприятного детского опыта. Дети из семей с насилием или хроническим стрессом несут этот опыт в каждой клетке — буквально. Это не означает фатализм: раннее вмешательство, терапия и создание безопасной среды могут снизить скорость дальнейшего укорачивания теломер даже у взрослых.",
8: " Блэкберн и Эпель показывают: это согласуется с общей логикой книги. Диеты богатые воспалительными продуктами повышают окислительный стресс который ускоряет укорачивание теломер. Антиоксиданты из разнообразных овощей и фруктов снижают его. Это не про конкретные суперфуды или добавки, а про общий паттерн питания на протяжении многих лет.",
9: " Блэкберн и Эпель показывают: это один из фундаментальных компромиссов биологии старения. Слишком много теломеразы — риск рака. Слишком мало — ускоренное старение. Эволюция нашла баланс но не оптимум ни для одного из рисков. Исследования точечной регуляции теломеразы — активной области в онкологии и геронтологии — могут стать основой следующего поколения препаратов.",
},
674: {
0: " Кэмпбелл показывает: исследование ценно своим масштабом и разнообразием. Китайские уезды 1983 года имели радикально разный рацион: одни почти не ели животных продуктов, другие ели их регулярно. Такого естественного разброса питания на одной популяции практически не существует в современном мире. Это делало исследование уникальной возможностью для наблюдения — при всех его методологических ограничениях.",
1: " Кэмпбелл показывает: лабораторные данные по казеину были ключевым открытием его карьеры. Оговорка которую он сам признаёт: это крысы с химически индуцированными опухолями — не самая точная модель человеческого рака. Переход от «казеин влияет на рост опухолей у крыс» к «молочные продукты вызывают рак у людей» — методологический прыжок который критики считают чрезмерным.",
2: " Кэмпбелл показывает: центральный тезис о цельной растительной диете более убедителен в части сердечно-сосудистых болезней чем в части рака. Орниш и Эссельстин показали обратимость коронарной болезни на строгой растительной диете — это клинически воспроизводимый результат. В части онкологии данные значительно слабее и их интерпретация остаётся дискуссионной в научном сообществе.",
3: " Кэмпбелл показывает: научные споры вокруг «Китайского исследования» — не уникальное явление, а норма для нутриционной эпидемиологии. Питание крайне сложно изучать: люди едят тысячи продуктов в разных комбинациях на протяжении десятилетий. Контролировать все переменные невозможно. Поэтому нутриционные рекомендации всегда основаны на несовершенных данных — это честное признание ограничений науки.",
4: " Кэмпбелл показывает: научный консенсус признаёт связь питания с онкологическим риском — но осторожно. Красное и переработанное мясо — доказанные канцерогены. Избыточный вес повышает риск множества видов рака. Клетчатка защищает от рака кишечника. Переход от этих осторожных выводов к утверждению что «животный белок как класс вызывает рак» — шаг который большинство онкологов не готовы сделать.",
5: " Кэмпбелл показывает: именно эта часть книги наиболее доказательно убедительна. Орниш опубликовал результаты в Lancet в 1990 году: строгая растительная диета плюс изменения образа жизни привели к регрессии атеросклеротических бляшек без лекарств. Это было революционным — медицина считала атеросклероз необратимым. Механизм работает через снижение холестерина и воспаления.",
6: " Кэмпбелл показывает: конфликт интересов в науке о питании — реальная и задокументированная проблема, не конспирология. Исследования финансируемые пищевой промышленностью систематически показывают более благоприятные результаты для продуктов финансирующей компании. Это не означает что все данные подделаны — но требует критического взгляда на источник финансирования при оценке исследований.",
7: " Кэмпбелл показывает: несмотря на дискуссионность его позиции о белке, основная рекомендация практически полезна. Большинство людей в развитых странах потребляют белок преимущественно из переработанных животных продуктов. Переход к растительным источникам — бобовым, тофу, орехам — изменяет не только количество белка но и весь нутриентный профиль рациона.",
8: " Кэмпбелл показывает: влияние книги на пищевые паттерны реально и измеримо. Многие клиники и диетологи начали рекомендовать цельную растительную диету для кардиологических пациентов после её выхода. Несмотря на методологические споры, практический вывод книги — есть больше цельных растительных продуктов — поддерживается широким научным консенсусом.",
9: " Кэмпбелл показывает: цельная растительная диета дешевле средней западной диеты — бобовые и злаки значительно дешевле мяса. Переход требует перестройки привычек и кулинарных навыков но не финансовых затрат. Для большинства людей основное препятствие — не стоимость и не вкус, а инерция привычек и социальные ситуации где еда разделяется с другими людьми.",
},
}

desc_fixes = {
    552: "Кишечник — второй мозг с 100 миллионами нейронов. Как микробиом управляет иммунитетом, настроением и весом — и почему это важнее, чем кажется.",
    553: "Не лечить болезни, а предотвращать их за десятилетия. Питер Аттиа — о том, как прожить дольше и при этом оставаться здоровым физически и ментально.",
    554: "Большинство хронических болезней предотвратимы едой. Грегер разбирает 15 причин смерти и показывает, что связь питания с каждой из них доказана наукой.",
    555: "Большинство людей дышат неправильно. Как нос, ритм и техника дыхания влияют на давление, сон и тревогу — Джеймс Нестор с доказательной базой.",
    556: "Пять мест на Земле с наибольшей концентрацией столетников. Что общего у Сардинии, Окинавы и других голубых зон и как применить это в своей жизни.",
    557: "Зебры не получают язву, а люди да. Роберт Сапольски о биологии стресса и о том, что хронический стресс делает с телом, мозгом и иммунитетом.",
    558: "Нейробиолог Джон Медина — о 12 правилах работы мозга и как применять их в обучении, работе и воспитании детей с опорой на нейронауку.",
    672: "Питер Аттиа предлагает новый взгляд на медицину: не лечить болезни, а предотвращать их за десятилетия. Наука о том, как прожить дольше и лучше.",
    673: "Нобелевский лауреат Блэкберн и психолог Эпель о теломерах. Как стресс, сон и образ жизни влияют на скорость биологического старения клеток.",
    674: "Масштабное исследование питания в 65 уездах Китая. Биохимик Колин Кэмпбелл — о связи животного белка с хроническими болезнями и растительной диете.",
}

count = 0
for b in books:
    bid = b["id"]
    if bid in appends:
        for i, t in enumerate(b.get("thoughts", [])):
            if i in appends[bid]:
                t["example"] += appends[bid][i]
                count += 1
    if bid in desc_fixes:
        b["description"] = desc_fixes[bid]

with open("/root/books/webapp/books.json", "w", encoding="utf-8") as f:
    json.dump(books, f, ensure_ascii=False, separators=(",",":"))
print("Fixed %s thoughts, %s descriptions" % (count, len(desc_fixes)))
